/** Platform-aware modifier key — bundle's Cy component. Shows ⌘ on Mac, "Ctrl +" on other platforms */
export const PlatformModifierKey = (props: { className?: string }) => {
  const isMac = React.useMemo(
    () =>
      navigator.platform.toUpperCase().indexOf('MAC') >= 0 ||
      navigator.userAgent.toUpperCase().indexOf('MAC') >= 0,
    []
  );
  return isMac ? (
    <CmdKeyIcon {...props} />
  ) : (
    <span className="text-text-500 font-normal">Ctrl +</span>
  );
};

